            Text(
              _titles[_currentIndex],
              style: TextStyle(
                color: AppConfig.textDarkColor,
                fontWeight: FontWeight.bold,
                fontSize: 20,
              ),
            ),
            Text(
              "SafeTask Sandbox Mode",
